  },
  "classification": "Natural Kind",
  "reasoning": "PhysicalObject is a rigid property because an instance cannot cease to be a physical object without ceasing to exist. It supplies its own global identity conditions (spatio-temporal continuity) and carries unity as it defines the boundaries of an intrinsic whole."
}

{
  "properties": {
    "rigidity": "+R",
